import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * TARIFF - freight charges over an alphanumeric code table, translated
 * from COBOL 85. Idiomatic variant: zero-based arrays.
 *
 * The zone-code and rate tables are filled once; each per-zone charge is
 * rounded to the cent and the BULK tier splits on the total.
 */
public final class Tariff {

    private static final BigDecimal PIC_9_5_V99 = new BigDecimal("100000");
    private static final BigDecimal PIC_9_6_V99 = new BigDecimal("1000000");
    private static final BigDecimal PIC_9_7_V99 = new BigDecimal("10000000");
    private static final BigDecimal THRESHOLD = new BigDecimal("50");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        BigDecimal weight = numval(in.readLine());

        // Zone codes and rates, zero-based.
        String[] zoneCode = new String[3];
        zoneCode[0] = "SEA";
        zoneCode[1] = "ROA";
        zoneCode[2] = "AIR";

        BigDecimal[] rate = new BigDecimal[3];
        rate[0] = new BigDecimal("1.25");
        rate[1] = new BigDecimal("0.85");
        rate[2] = new BigDecimal("0.45");

        BigDecimal chg1 = weight.multiply(rate[0]).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_6_V99);
        BigDecimal chg2 = weight.multiply(rate[1]).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_6_V99);
        BigDecimal chg3 = weight.multiply(rate[2]).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_6_V99);
        BigDecimal total = chg1.add(chg2).add(chg3).remainder(PIC_9_7_V99);
        String tier = total.compareTo(THRESHOLD) > 0 ? "BULK" : "STD ";

        StringBuilder out = new StringBuilder();
        out.append("C1=").append(zoneCode[0]).append('\n');
        out.append("C2=").append(zoneCode[1]).append('\n');
        out.append("C3=").append(zoneCode[2]).append('\n');
        out.append("F1=").append(chg1.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("F2=").append(chg2.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("F3=").append(chg3.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("TOTAL=").append(total.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("TIER=").append(tier).append('\n');
        System.out.print(out);
    }

    private static BigDecimal numval(String s) {
        try {
            return new BigDecimal(s.trim()).setScale(2, RoundingMode.DOWN).remainder(PIC_9_5_V99);
        } catch (NumberFormatException e) {
            System.err.println("TARIFF: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO;
        }
    }
}
